#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    /* Process input based on kind */
    switch (input.kind) {
    case CONTROLLER_INPUT_TURBIDITY:
        /* Valid turbidity input - update state */
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = input.now_ms;

        /* If we had a stale level, now both sensors are valid */
        if (!controller->has_valid_level && controller->has_valid_turbidity) {
            controller->has_valid_level = true;
            controller->last_level = 0;
            controller->last_level_ms = 0U;
        }

        /* If we had a stale turbidity, now both sensors are valid */
        if (!controller->has_valid_turbidity && controller->has_valid_level) {
            controller->has_valid_turbidity = true;
            controller->last_turbidity_ntu = 0;
            controller->last_turbidity_ms = 0U;
        }

        /* Check for sensor timeout on turbidity */
        if (controller->has_valid_turbidity && 
            input.now_ms - controller->last_turbidity_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
            controller->has_valid_turbidity = false;
            controller->has_valid_level = false;
            controller->clear_streak_count = 0;
            controller->settling_started_ms = 0U;
            controller_set_safe_idle(controller);
        } else if (!controller->has_valid_turbidity && 
                   input.now_ms - controller->last_turbidity_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
            /* Stale turbidity from last frame */
            controller->has_valid_turbidity = false;
            controller->has_valid_level = false;
            controller->clear_streak_count = 0;
            controller->settling_started_ms = 0U;
            controller_set_safe_idle(controller);
        }
        break;

    case CONTROLLER_INPUT_LEVEL:
        /* Valid level input - update state */
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;

        /* If we had a stale turbidity, now both sensors are valid */
        if (!controller->has_valid_turbidity && controller->has_valid_level) {
            controller->has_valid_turbidity = true;
            controller->last_turbidity_ntu = 0;
            controller->last_turbidity_ms = 0U;
        }

        /* Check for sensor timeout on level */
        if (controller->has_valid_level && 
            input.now_ms - controller->last_level_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
            controller->has_valid_turbidity = false;
            controller->has_valid_level = false;
            controller->clear_streak_count = 0;
            controller->settling_started_ms = 0U;
            controller_set_safe_idle(controller);
        } else if (!controller->has_valid_level && 
                   input.now_ms - controller->last_level_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
            /* Stale level from last frame */
            controller->has_valid_turbidity = false;
            controller->has_valid_level = false;
            controller->clear_streak_count = 0;
            controller->settling_started_ms = 0U;
            controller_set_safe_idle(controller);
        }
        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        /* Timeout event - force safe idle */
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
        break;

    case CONTROLLER_INPUT_INVALID_TURBIDITY:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        /* Invalid input - force safe idle */
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
        break;

    case CONTROLLER_INPUT_NONE:
    default:
        /* No valid input - force safe idle */
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
        break;
    }

    /* State machine logic */
    bool level_below_complete = controller->last_level < CONTROLLER_COMPLETE_LEVEL;

    if (controller->state == CONTROLLER_STATE_SAFE_IDLE) {
        /* Stay in SAFE_IDLE until both sensors have been seen validly */
        if (controller->has_valid_turbidity && controller->has_valid_level) {
            /* Both sensors are valid - now process based on sensor values */

            /* If level < 15, stay in COMPLETE with filter off and drain closed */
            if (level_below_complete) {
                controller->state = CONTROLLER_STATE_COMPLETE;
                output.filter_on = false;
                output.drain_open = false;
                output.state_name = "STATE COMPLETE";
                output.changed = true;
            } else {
                /* Level >= 40 and both sensors valid - start filtering */
                if (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    controller->state = CONTROLLER_STATE_FILTERING;
                    controller->filter_on = true;
                    controller->drain_open = false;
                    output.filter_on = true;
                    output.drain_open = false;
                    output.state_name = "STATE FILTERING";
                    output.changed = true;
                } else {
                    /* Turbidity <= 35, both sensors valid - stay in SAFE_IDLE */
                    controller->state = CONTROLLER_STATE_SAFE_IDLE;
                    output.filter_on = false;
                    output.drain_open = false;
                    output.state_name = "STATE SAFE_IDLE";
                }
            }
        } else {
            /* At least one sensor is stale - stay in SAFE_IDLE */
            controller->state = CONTROLLER_STATE_SAFE_IDLE;
            output.filter_on = false;
            output.drain_open = false;
            output.state_name = "STATE SAFE_IDLE";
        }
    }
    else if (controller->state == CONTROLLER_STATE_FILTERING) {
        /* Count clear streak using valid TURB inputs only */
        if (controller->has_valid_turbidity) {
            if (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                /* Clear sample - increment streak */
                controller->clear_streak_count++;
            } else {
                /* Dirty sample - reset streak */
                controller->clear_streak_count = 0;
            }

            /* If turbidity > 35 and level >= 40, keep filtering */
            if (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU && 
                controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                controller->state = CONTROLLER_STATE_FILTERING;
                output.filter_on = true;
                output.drain_open = false;
                output.state_name = "STATE FILTERING";
                output.changed = true;
            }

            /* When clear streak reaches 3 while level >= 40, enter SETTLING */
            if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED &&
                controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                controller->state = CONTROLLER_STATE_SETTLING;
                controller->filter_on = false;
                controller->drain_open = false;
                output.filter_on = false;
                output.drain_open = false;
                output.state_name = "STATE SETTLING";
                output.changed = true;
            }
        } else {
            /* No valid turbidity - reset streak and go to safe idle */
            controller->clear_streak_count = 0;
            controller->has_valid_turbidity = false;
            controller_set_safe_idle(controller);
            output.filter_on = false;
            output.drain_open = false;
            output.state_name = "STATE SAFE_IDLE";
            output.changed = true;
        }
    }
    else if (controller->state == CONTROLLER_STATE_SETTLING) {
        /* Track settling time */
        controller->settling_started_ms = input.now_ms;

        /* If valid TURB > 40 arrives, reset streak and return to FILTERING */
        if (controller->has_valid_turbidity && controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
            controller->clear_streak_count = 0;
            controller->state = CONTROLLER_STATE_FILTERING;
            controller->filter_on = true;
            controller->drain_open = false;
            output.filter_on = true;
            output.drain_open = false;
            output.state_name = "STATE FILTERING";
            output.changed = true;
        } else {
            /* Check if settling has lasted >= 400ms with latest clear sample and level >= 40 */
            uint32_t settling_elapsed_ms = input.now_ms - controller->settling_started_ms;

            if (settling_elapsed_ms >= CONTROLLER_SETTLING_MS &&
                controller->has_valid_turbidity &&
                controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU &&
                controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {

                /* Enter DRAINING */
                controller->state = CONTROLLER_STATE_DRAINING;
                controller->filter_on = false;
                controller->drain_open = true;
                output.filter_on = false;
                output.drain_open = true;
                output.state_name = "STATE DRAINING";
                output.changed = true;
            } else {
                /* Still settling - stay in SETTLING */
                controller->state = CONTROLLER_STATE_SETTLING;
                output.filter_on = false;
                output.drain_open = false;
                output.state_name = "STATE SETTLING";
            }
        }
    }
    else if (controller->state == CONTROLLER_STATE_DRAINING) {
        /* If valid TURB > 50 arrives and level >= 40, close drain and restart filtering */
        if (controller->has_valid_turbidity && controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU &&
            controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {

            controller->state = CONTROLLER_STATE_FILTERING;
            controller->filter_on = true;
            controller->drain_open = false;
            controller->clear_streak_count = 0;
            output.filter_on = true;
            output.drain_open = false;
            output.state_name = "STATE FILTERING";
            output.changed = true;
        } else {
            /* Continue draining */
            controller->state = CONTROLLER_STATE_DRAINING;
            output.filter_on = false;
            output.drain_open = true;
            output.state_name = "STATE DRAINING";
        }
    }
    else if (controller->state == CONTROLLER_STATE_COMPLETE) {
        /* Level < 15 - stay in COMPLETE with filter off and drain closed */
        controller->state = CONTROLLER_STATE_COMPLETE;
        output.filter_on = false;
        output.drain_open = false;
        output.state_name = "STATE COMPLETE";
    }

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_filter_on != controller->filter_on) ||
        (previous_drain_open != controller->drain_open) ||
        (previous_state != controller->state);

    return output;
}

